let select=e=>{const t=document.querySelector(`${e} > .select__header`),n=document.querySelectorAll(`${e} .select__option`);t.addEventListener("click",(function(){this.closest(e).classList.toggle("is-active")}));for(let r=0;r<n.length;r++)n[r].addEventListener("click",(function(){this.closest(e).classList.remove("is-active"),t.innerText=this.innerText}))};const sliderOne=new Swiper(".creo__slider-one",{loop:!0,navigation:{prevEl:".creo__btn-prev-one",nextEl:".creo__btn-next-one"},slidesPerView:5,spaceBetween:50,grabCursor:!0}),sliderTwo=new Swiper(".creo__slider-two",{loop:!0,navigation:{prevEl:".creo__btn-prev-two",nextEl:".creo__btn-next-two"},slidesPerView:5,spaceBetween:50,grabCursor:!0}),sliderThree=new Swiper(".blog__slider",{navigation:{prevEl:".blog__btn-prev",nextEl:".blog__btn-next"},pagination:{el:".blog__pagination",clickable:!0},slidesPerView:4,spaceBetween:27,grabCursor:!0,slidesPerGroup:4});select(".services__select");